const raw = $input.first().json;
const body = typeof raw.data === 'string' ? JSON.parse(raw.data) : raw;

if (body?.retorno?.status !== 'OK') {
  throw new Error('Erro na API V2: ' + JSON.stringify(body?.retorno));
}

const pedidos = (body?.retorno?.pedidos || []).map(p => p.pedido || p);
const numeroPaginas = parseInt(body?.retorno?.numero_paginas || 1);
const paginaAtual = parseInt(body?.retorno?.pagina || 1);

// Salva info de paginação em cada item
return pedidos.map(p => ({ 
  json: { 
    id: p.id, 
    numero: p.numero,
    _pagina_atual: paginaAtual,
    _numero_paginas: numeroPaginas
  } 
}));

const raw = $input.first().json;
const body = typeof raw.data === 'string' ? JSON.parse(raw.data) : raw;

if (body?.retorno?.status !== 'OK') {
  throw new Error('Erro ao obter pedido: ' + JSON.stringify(body?.retorno));
}

const p = body?.retorno?.pedido || {};
const cliente = p.cliente || {};
const itens = p.itens || [];

function formatDateBRtoISO(input) {
  if (!input || typeof input !== 'string') return null;
  const [day, month, year] = input.split('/');
  if (!day || !month || !year) return null;
  return `${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
}

function formatNumber(input) {
  if (input === null || input === undefined || input === '') return null;
  // API V2 já usa ponto decimal ("26.01000000"), só faz parseFloat
  const num = parseFloat(String(input).replace(/\s+/g, ''));
  return isNaN(num) ? null : num;
}

const totalProdutos  = formatNumber(p.total_produtos) || 0;
const valorFrete     = formatNumber(p.valor_frete) || 0;
const valorDesconto  = formatNumber(p.valor_desconto) || 0;
const outrasDespesas = formatNumber(p.outras_despesas) || 0;

const itensParsed = itens.map(i => {
  const item  = i.item || i;
  const qtd   = formatNumber(item.quantidade) || 1;
  const vUnit = formatNumber(item.valor_unitario) || 0;
  return { ...item, qtd, vUnit, subtotal: parseFloat((qtd * vUnit).toFixed(2)) };
});

const totalSubtotal = itensParsed.reduce((acc, i) => acc + i.subtotal, 0);

const orders = itensParsed.map(produto => {
  const proporcao       = totalSubtotal > 0 ? produto.subtotal / totalSubtotal : 0;
  const descontoItem    = parseFloat((produto.subtotal - totalProdutos * proporcao).toFixed(2));
  const freteRateado    = parseFloat((valorFrete * proporcao).toFixed(2));
  const descontoRateado = parseFloat((valorDesconto * proporcao).toFixed(2));
  const despesasRateado = parseFloat((outrasDespesas * proporcao).toFixed(2));

  return {
    id:                                  p.id || null,
    numero_do_pedido:                    p.numero || null,
    data:                                formatDateBRtoISO(p.data_pedido),
    data_prevista:                       formatDateBRtoISO(p.data_prevista) || null,
    id_contato:                          cliente.id || null,
    nome_do_contato:                     cliente.nome || null,
    tipo_de_pessoa:                      cliente.tipo_pessoa || null,
    cpf_cnpj:                            cliente.cpf_cnpj || null,
    rg_ie:                               cliente.ie || cliente.rg || null,
    cep:                                 cliente.cep || null,
    municipio:                           cliente.cidade || null,
    uf:                                  cliente.uf || null,
    endereco:                            cliente.endereco || null,
    endereco_nro:                        cliente.numero || null,
    complemento:                         cliente.complemento || null,
    bairro:                              cliente.bairro || null,
    fone:                                cliente.fone || null,
    celular:                             cliente.celular || null,
    email:                               cliente.email || null,
    desconto_do_pedido_porcento_ou_valor: valorDesconto,
    frete_pedido:                        valorFrete,
    observacoes:                         p.obs || null,
    situacao:                            p.situacao || null,
    id_produto:                          produto.id_produto || null,
    descricao:                           produto.descricao || null,
    quantidade:                          produto.qtd,
    valor_unitario:                      produto.vUnit,
    desconto_item:                       descontoItem,
    codigo_de_rastreamento:              p.codigo_rastreamento || null,
    numero_da_ordem_de_compra:           p.numero_ordem_compra || null,
    vendedor:                            p.id_vendedor ? String(p.id_vendedor) : null,
    despesas_pedido:                     outrasDespesas,
    desconto_pedido_rateado:             descontoRateado,
    frete_pedido_rateado:                freteRateado,
    despesas_pedido_rateado:             despesasRateado,
    destinatario:                        null,
    cpf_cnpj_entrega:                    null,
    cep_entrega:                         null,
    municipio_entrega:                   null,
    uf_entrega:                          null,
    endereco_entrega:                    null,
    endereco_nro_entrega:                null,
    complemento_entrega:                 null,
    bairro_entrega:                      null,
    fone_entrega:                        null,
    codigo_sku:                          produto.codigo || null,
    filial:                              '001'
  };
});

return orders.map(row => ({ json: row }));

